-- ============================================================
-- Seed 025: Evidence Template Library
-- 200+ evidence templates covering ISO 27001, PCI DSS, NIST 800-53
-- ============================================================

-- ============================================================
-- ISO 27001:2022 — Organizational Controls (A.5)
-- ============================================================

INSERT INTO evidence_templates (framework_control_code, framework_code, name, description, evidence_category, collection_method, collection_instructions, collection_frequency, typical_collection_time_minutes, validation_rules, acceptance_criteria, common_rejection_reasons, difficulty, auditor_priority, is_system, tags) VALUES
('A.5.1', 'ISO27001', 'Information Security Policy Document', 'Current approved information security policy signed by senior management.', 'policy_document', 'document_review', 'Obtain the current information security policy document. Verify it has been approved by senior management with a signature and date. Check the document version number, effective date, and next review date. Ensure the policy covers scope, objectives, principles, roles, and responsibilities.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}},{"rule_type":"contains_text","params":{"text":"approved"}}]', 'Policy must be signed, dated within the last 12 months, and include scope and objectives.', '{"Missing management signature","Policy older than 12 months","No version control information","Missing scope definition"}', 'easy', 'critical', true, '{"policy","governance","management-review"}'),

('A.5.1', 'ISO27001', 'Policy Communication Records', 'Evidence that the information security policy has been communicated to all employees.', 'email_confirmation', 'document_review', 'Collect records showing the information security policy was distributed to all employees. This can include email distribution logs, intranet publication records, training system acknowledgement reports, or signed acknowledgement forms. Verify the communication reached all active employees.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Communication records must cover all active employees within the last 12 months.', '{"Incomplete distribution list","No acknowledgement tracking","Records older than 12 months"}', 'moderate', 'high', true, '{"policy","communication","awareness"}'),

('A.5.2', 'ISO27001', 'Roles and Responsibilities Matrix', 'Document defining information security roles and responsibilities.', 'document', 'document_review', 'Obtain the RACI matrix or roles and responsibilities document for information security. Verify it covers all key roles including CISO, IT Security Manager, Data Protection Officer, system owners, and asset custodians. Check alignment with organizational structure.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Matrix must be current, approved, and cover all security-relevant roles.', '{"Outdated organizational structure","Missing key roles","No approval date"}', 'moderate', 'high', true, '{"roles","responsibilities","governance"}'),

('A.5.3', 'ISO27001', 'Segregation of Duties Documentation', 'Evidence of implemented segregation of duties for critical processes.', 'configuration_export', 'system_export', 'Export access control configurations showing segregation of duties enforcement. Include role-based access control configurations, incompatible role matrices, and any compensating controls for exceptions. Document how critical functions (e.g., change request, approval, implementation) are separated.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Configuration must demonstrate separation of critical functions with no conflicting role assignments.', '{"Conflicting role assignments found","Missing compensating controls for exceptions","Configuration export incomplete"}', 'hard', 'high', true, '{"access-control","segregation","rbac"}'),

('A.5.4', 'ISO27001', 'Management Responsibility Acknowledgements', 'Signed acknowledgements from management regarding security responsibilities.', 'document', 'document_review', 'Collect signed acknowledgement forms from all management personnel confirming they understand and accept their information security responsibilities. Include records of management briefings and responsibility acceptance documentation.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'All managers must have signed current acknowledgement forms.', '{"Missing signatures from key managers","Forms older than 12 months"}', 'easy', 'medium', true, '{"management","responsibility","acknowledgement"}'),

('A.5.5', 'ISO27001', 'Authority Contact Register', 'Up-to-date register of contacts with relevant authorities.', 'document', 'document_review', 'Maintain and provide the register of contacts with relevant authorities including data protection authorities, law enforcement, regulatory bodies, and emergency services. Verify contact details are current and the register has been reviewed recently.', 'semi_annually', 10, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'Register must contain current contact details for all relevant authorities.', '{"Outdated contact information","Missing key regulatory contacts"}', 'easy', 'medium', true, '{"contacts","authorities","incident-response"}'),

('A.5.6', 'ISO27001', 'Specialist Group Memberships', 'Evidence of participation in specialist security groups and forums.', 'document', 'document_review', 'Document memberships in specialist security groups, professional forums, and information sharing communities. Include membership certificates, meeting attendance records, and evidence of active participation in threat intelligence sharing.', 'annually', 10, '[{"rule_type":"file_not_empty"}]', 'Evidence of active membership in at least one relevant security forum or group.', '{"Lapsed membership","No evidence of active participation"}', 'trivial', 'low', true, '{"threat-intelligence","community","networking"}'),

('A.5.7', 'ISO27001', 'Threat Intelligence Reports', 'Records of threat intelligence collection and analysis activities.', 'system_report', 'automated_pull', 'Export threat intelligence reports from your threat intelligence platform or SIEM. Include threat briefings, vulnerability advisories processed, and records of how threat intelligence was used to inform security decisions. Document the sources and frequency of intelligence gathering.', 'monthly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Monthly threat intelligence summary with evidence of analysis and action taken.', '{"No analysis of threat data","Raw data only without assessment","Missing action items"}', 'hard', 'high', true, '{"threat-intelligence","monitoring","risk"}'),

('A.5.8', 'ISO27001', 'Project Security Assessment Records', 'Evidence of security considerations in project management.', 'document', 'document_review', 'Collect security assessment records from recent projects. Include security requirements specifications, risk assessments performed during project planning, security design reviews, and security acceptance testing results. Sample at least 3 recent projects.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Security assessments completed for all projects with identified risks addressed.', '{"No security requirements documented","Risk assessment missing","No evidence of security testing"}', 'moderate', 'medium', true, '{"project-management","risk-assessment","sdlc"}'),

('A.5.9', 'ISO27001', 'Information Asset Inventory', 'Complete inventory of information assets with ownership assigned.', 'system_report', 'system_export', 'Export the complete information asset inventory from the asset management system. Verify each asset has an assigned owner, classification level, and location. The inventory should include hardware, software, data assets, services, and supporting infrastructure.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Inventory must be complete, current, and include ownership for all assets.', '{"Missing asset classifications","Unassigned asset owners","Stale inventory data"}', 'moderate', 'critical', true, '{"asset-management","inventory","classification"}'),

('A.5.10', 'ISO27001', 'Acceptable Use Policy and Acknowledgements', 'Acceptable use policy with staff acknowledgement records.', 'policy_document', 'document_review', 'Provide the current acceptable use policy covering information assets, internet use, email, removable media, and BYOD. Include signed acknowledgement forms or electronic acceptance records from all employees demonstrating they have read and accepted the policy.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Policy current and acknowledged by all employees.', '{"Missing employee acknowledgements","Policy not updated for current technology","BYOD not covered"}', 'easy', 'high', true, '{"acceptable-use","policy","awareness"}'),

('A.5.11', 'ISO27001', 'Asset Return Records', 'Evidence of asset return process upon employment termination.', 'document', 'document_review', 'Collect records of asset returns from employees who have left the organization in the review period. Include asset return checklists, IT equipment handover forms, access card return records, and sign-off from IT confirming all assets were returned and accounts deactivated.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'All departing employees must have completed asset return process.', '{"Incomplete return checklists","Missing IT sign-off","Outstanding unreturned assets"}', 'moderate', 'medium', true, '{"asset-management","offboarding","hr"}'),

('A.5.12', 'ISO27001', 'Information Classification Scheme', 'Documented information classification scheme with handling procedures.', 'policy_document', 'document_review', 'Obtain the information classification scheme document including classification levels (e.g., Public, Internal, Confidential, Restricted), labeling requirements, handling procedures for each level, and declassification rules. Verify alignment with legal and regulatory requirements.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Classification scheme must define all levels with clear handling procedures.', '{"Missing handling procedures","No labeling requirements","Scheme not aligned with regulations"}', 'moderate', 'high', true, '{"classification","data-protection","policy"}'),

('A.5.13', 'ISO27001', 'Information Labeling Samples', 'Evidence of information labeling implementation.', 'screenshot', 'screenshot_capture', 'Capture screenshots or examples showing information labeling in practice. Include labeled documents, email classifications, database field markings, and system labels. Demonstrate labeling across different media types (electronic, physical, verbal communication protocols).', 'semi_annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'Evidence of consistent labeling across multiple information types and media.', '{"Inconsistent labeling","Missing labels on sensitive documents","Physical media not labeled"}', 'easy', 'medium', true, '{"classification","labeling","data-protection"}'),

('A.5.14', 'ISO27001', 'Information Transfer Policy and Records', 'Policy and evidence of secure information transfer procedures.', 'policy_document', 'document_review', 'Provide the information transfer policy covering electronic, physical, and verbal transfers. Include evidence of secure transfer mechanisms in use such as encrypted email logs, secure file transfer logs, courier tracking records for physical media, and non-disclosure agreements for verbal disclosures.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Transfer policy documented with evidence of secure transfers in practice.', '{"No encryption for electronic transfers","Missing NDA for third-party transfers","Untracked physical media transfers"}', 'moderate', 'high', true, '{"data-transfer","encryption","policy"}'),

-- A.5.15 to A.5.37 (Access Control, Identity, etc.)
('A.5.15', 'ISO27001', 'Access Control Policy Document', 'Documented access control policy covering logical and physical access.', 'policy_document', 'document_review', 'Obtain the access control policy document. Verify it defines access control rules, user access provisioning/deprovisioning procedures, privileged access management, and access review requirements. Ensure alignment with business needs and least privilege principle.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Policy must cover all aspects of logical and physical access control.', '{"Missing privileged access section","No review schedule defined","Least privilege not addressed"}', 'moderate', 'critical', true, '{"access-control","policy","identity"}'),

('A.5.16', 'ISO27001', 'Identity Management Records', 'User account lifecycle management evidence.', 'system_report', 'system_export', 'Export user account management records from the identity management system. Include evidence of account provisioning workflows, approval records, account modification logs, and account deprovisioning records. Demonstrate the full lifecycle from creation to deletion.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Complete user lifecycle records with proper approvals at each stage.', '{"Missing approval records","Orphaned accounts found","No deprovisioning evidence"}', 'moderate', 'high', true, '{"identity","account-management","provisioning"}'),

('A.5.17', 'ISO27001', 'Authentication Configuration Evidence', 'System authentication mechanism configurations.', 'configuration_export', 'system_export', 'Export authentication configurations from key systems including password policy settings, multi-factor authentication configuration, session timeout settings, and failed login lockout policies. Cover Active Directory, VPN, cloud services, and critical applications.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Authentication configurations must enforce MFA, strong passwords, and account lockout.', '{"MFA not enabled on critical systems","Weak password policy settings","No session timeout configured"}', 'moderate', 'critical', true, '{"authentication","mfa","password-policy"}'),

('A.5.18', 'ISO27001', 'Access Rights Review Report', 'Periodic user access rights review results.', 'system_report', 'system_export', 'Generate or export access rights review reports showing periodic review of user permissions. Include the review scope, reviewers, findings (inappropriate access identified), remediation actions taken, and sign-off by system owners. Cover all critical systems.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Access review completed for all critical systems with remediation of findings.', '{"Systems not covered in review","No remediation of findings","Missing system owner sign-off"}', 'hard', 'critical', true, '{"access-review","user-access","periodic-review"}'),

('A.5.19', 'ISO27001', 'Supplier Security Agreements', 'Information security clauses in supplier agreements.', 'document', 'document_review', 'Collect sample supplier agreements and contracts demonstrating inclusion of information security requirements. Include security SLAs, data protection clauses, right to audit provisions, incident notification requirements, and termination data handling procedures.', 'annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Agreements must include security requirements, data protection, and audit rights.', '{"Missing security SLAs","No right to audit clause","Data protection clauses absent"}', 'moderate', 'high', true, '{"supplier","vendor","contracts"}'),

('A.5.20', 'ISO27001', 'Supplier Security Requirements', 'Documented security requirements for suppliers.', 'document', 'document_review', 'Provide the documented security requirements shared with suppliers covering access controls, data handling, encryption requirements, incident reporting obligations, and compliance verification procedures. Include evidence of requirements being communicated.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Clear security requirements documented and communicated to all suppliers.', '{"Requirements not communicated","Missing encryption standards","No incident reporting requirements"}', 'moderate', 'high', true, '{"supplier","requirements","vendor-management"}'),

('A.5.21', 'ISO27001', 'ICT Supply Chain Security Assessment', 'Evidence of ICT supply chain risk management.', 'document', 'document_review', 'Document the ICT supply chain risk assessment covering critical technology providers, software dependencies, and hardware supply chain. Include risk assessment methodology, identified risks, mitigation measures, and ongoing monitoring approach.', 'annually', 35, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Supply chain risks identified and mitigated for all critical ICT components.', '{"Missing critical supplier assessment","No mitigation measures","Software dependencies not analyzed"}', 'hard', 'high', true, '{"supply-chain","risk-assessment","vendor"}'),

('A.5.22', 'ISO27001', 'Supplier Monitoring Records', 'Ongoing monitoring of supplier security performance.', 'system_report', 'document_review', 'Collect records of supplier security monitoring activities including periodic security assessments, SLA compliance reports, incident reports from suppliers, audit reports, and evidence of corrective actions for identified issues.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Regular monitoring activities documented with follow-up on findings.', '{"No monitoring schedule","Missing SLA reports","Findings not tracked to resolution"}', 'moderate', 'medium', true, '{"supplier","monitoring","performance"}'),

('A.5.23', 'ISO27001', 'Cloud Service Security Configuration', 'Security configuration evidence for cloud service usage.', 'configuration_export', 'system_export', 'Export cloud service security configurations including encryption settings, access controls, logging configuration, network security groups, and data residency settings. Cover all cloud providers (AWS, Azure, GCP) in use. Include cloud security posture management reports if available.', 'quarterly', 35, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Cloud services configured with encryption, access controls, and logging enabled.', '{"Encryption not enabled at rest","Overly permissive security groups","Logging not configured","Data residency violations"}', 'hard', 'critical', true, '{"cloud","configuration","encryption","aws","azure"}'),

('A.5.24', 'ISO27001', 'Incident Management Plan and Procedures', 'Documented incident management plan with response procedures.', 'procedure_document', 'document_review', 'Obtain the incident management plan including incident classification scheme, escalation procedures, communication plan, roles and responsibilities during incidents, evidence preservation procedures, and post-incident review process.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Plan must be current, approved, and cover the full incident lifecycle.', '{"Missing classification scheme","No escalation procedures","Communication plan absent"}', 'moderate', 'critical', true, '{"incident-management","response","plan"}'),

('A.5.25', 'ISO27001', 'Security Incident Log', 'Record of security incidents and their handling.', 'system_report', 'system_export', 'Export the security incident log from the incident management system. Include incident ID, classification, timeline, affected systems, root cause, containment actions, resolution, and lessons learned for each incident. Cover the review period.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Complete incident log with resolution and lessons learned for all incidents.', '{"Missing root cause analysis","Incomplete incident timelines","No lessons learned documented"}', 'moderate', 'critical', true, '{"incident-management","logging","response"}'),

('A.5.26', 'ISO27001', 'Incident Response Training Records', 'Evidence of incident response training and exercises.', 'training_record', 'document_review', 'Collect training records for incident response team members. Include training attendance, tabletop exercise records, simulation results, and competency assessments. Demonstrate that all incident response team members are trained and exercises are conducted regularly.', 'semi_annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'All incident response team members trained with at least one exercise per year.', '{"Team members not trained","No exercise conducted","Missing competency assessments"}', 'moderate', 'high', true, '{"incident-response","training","exercises"}'),

('A.5.27', 'ISO27001', 'Lessons Learned Reports', 'Post-incident lessons learned documentation.', 'document', 'document_review', 'Collect post-incident review reports documenting lessons learned. Include root cause analysis, timeline of events, effectiveness of response, improvement recommendations, and evidence that recommendations were implemented.', 'quarterly', 15, '[{"rule_type":"file_not_empty"}]', 'Lessons learned documented for all significant incidents with improvement actions.', '{"No improvement actions identified","Actions not tracked to completion","Root cause not addressed"}', 'moderate', 'medium', true, '{"incident-response","lessons-learned","improvement"}'),

('A.5.28', 'ISO27001', 'Evidence Collection Procedures', 'Procedures for evidence collection during incidents.', 'procedure_document', 'document_review', 'Provide documented evidence collection and preservation procedures for security incidents. Include chain of custody procedures, forensic imaging procedures, log preservation methods, and legal requirements for evidence handling.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Procedures must cover evidence preservation, chain of custody, and legal requirements.', '{"No chain of custody procedure","Missing forensic procedures","Legal requirements not addressed"}', 'hard', 'medium', true, '{"forensics","evidence-collection","legal"}'),

('A.5.29', 'ISO27001', 'Business Continuity Security Requirements', 'Information security requirements in business continuity plans.', 'document', 'document_review', 'Review business continuity plans and extract evidence of information security considerations. Include security requirements for disaster recovery sites, backup security controls, communication security during incidents, and access control during crisis operations.', 'annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Security requirements documented in BCP including DR site security.', '{"No security requirements in BCP","DR site security not addressed","Backup security gaps"}', 'hard', 'high', true, '{"business-continuity","disaster-recovery","security"}'),

('A.5.30', 'ISO27001', 'ICT Readiness Test Results', 'ICT readiness for business continuity testing results.', 'test_result', 'document_review', 'Collect results from ICT business continuity testing. Include disaster recovery test results, failover test records, backup restoration test results, and recovery time achievement evidence. Document any gaps identified and remediation plans.', 'semi_annually', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'DR tests conducted with documented results and recovery time validation.', '{"No DR test conducted","Recovery targets not met","Backup restoration failures","Missing test documentation"}', 'hard', 'critical', true, '{"disaster-recovery","testing","business-continuity"}'),

('A.5.31', 'ISO27001', 'Legal and Regulatory Requirements Register', 'Register of applicable legal and regulatory requirements.', 'document', 'document_review', 'Provide the register of applicable legal, statutory, regulatory, and contractual requirements related to information security. Include GDPR, industry regulations, contractual obligations, and evidence of periodic review for currency.', 'semi_annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'Complete register of applicable requirements with evidence of regular review.', '{"Incomplete register","Missing recent regulatory changes","No review evidence"}', 'moderate', 'high', true, '{"legal","regulatory","compliance"}'),

('A.5.32', 'ISO27001', 'Intellectual Property Compliance Records', 'Evidence of intellectual property rights compliance.', 'document', 'document_review', 'Provide evidence of compliance with intellectual property rights including software license inventory and compliance reports, use of license management tools, policy on use of proprietary material, and records of periodic license audits.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'License compliance verified with no unauthorized software use.', '{"Unlicensed software found","Missing license inventory","No compliance audit conducted"}', 'moderate', 'medium', true, '{"intellectual-property","licensing","compliance"}'),

('A.5.33', 'ISO27001', 'Records Protection Evidence', 'Evidence of protection of records from loss and destruction.', 'configuration_export', 'system_export', 'Export evidence of records protection controls including backup configurations, retention schedules, access controls on record storage, encryption of records at rest, and disaster recovery provisions for critical records.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Records protected with backups, access controls, and retention policies.', '{"No retention schedule","Backups not encrypted","Missing access controls on archives"}', 'moderate', 'medium', true, '{"records-management","backup","retention"}'),

('A.5.34', 'ISO27001', 'Privacy Impact Assessment Records', 'Completed privacy impact assessments for personal data processing.', 'document', 'document_review', 'Collect completed Data Protection Impact Assessments (DPIAs) for high-risk processing activities. Include the assessment methodology, identified risks, mitigation measures, and DPO consultation records. Verify assessments are conducted before processing begins.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'DPIAs completed for all high-risk processing with risk mitigations.', '{"DPIA not conducted before processing","Missing DPO consultation","Risk mitigations incomplete"}', 'hard', 'critical', true, '{"privacy","dpia","gdpr","data-protection"}'),

('A.5.35', 'ISO27001', 'Independent Security Review Report', 'Results of independent review of information security.', 'audit_trail', 'document_review', 'Provide the most recent independent security review or audit report. Include scope, methodology, findings, risk ratings, and management response. Verify the review was conducted by qualified independent assessors.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Independent review completed by qualified assessors with management response.', '{"Review not independent","Missing management response","Findings not risk-rated"}', 'easy', 'critical', true, '{"audit","independent-review","assessment"}'),

('A.5.36', 'ISO27001', 'Security Standards Compliance Evidence', 'Evidence of compliance with security policies and standards.', 'system_report', 'automated_scan', 'Run compliance scans against security standards and policies. Export configuration compliance reports from vulnerability scanners, CIS benchmark scans, and security baseline assessments. Include exception management records for any deviations.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Compliance scan results showing adherence to security standards.', '{"Critical non-conformities found","Missing compensating controls","Exception records incomplete"}', 'moderate', 'high', true, '{"compliance","standards","scanning","cis-benchmark"}'),

('A.5.37', 'ISO27001', 'Documented Operating Procedures', 'Documented operating procedures for information processing.', 'procedure_document', 'document_review', 'Collect documented operating procedures for critical information processing facilities. Include procedures for system start-up/shutdown, backup operations, maintenance, error handling, and contact lists. Verify procedures are current, approved, and accessible.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Operating procedures documented, current, approved, and accessible to relevant staff.', '{"Procedures outdated","Missing approval","Not accessible to operations staff"}', 'easy', 'medium', true, '{"operations","procedures","documentation"}');

-- ============================================================
-- ISO 27001:2022 — People Controls (A.6)
-- ============================================================

INSERT INTO evidence_templates (framework_control_code, framework_code, name, description, evidence_category, collection_method, collection_instructions, collection_frequency, typical_collection_time_minutes, validation_rules, acceptance_criteria, common_rejection_reasons, difficulty, auditor_priority, is_system, tags) VALUES
('A.6.1', 'ISO27001', 'Personnel Screening Records', 'Background verification checks for new employees.', 'document', 'document_review', 'Collect background verification records for employees hired during the review period. Include criminal record checks, reference checks, qualification verifications, and identity verification. Ensure screening is proportionate to the role and compliant with local laws.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Background checks completed for all new hires before or shortly after employment start.', '{"Checks not completed before employment","Missing criminal record verification","No reference checks conducted"}', 'moderate', 'high', true, '{"hr","screening","background-check"}'),

('A.6.2', 'ISO27001', 'Employment Terms and Conditions', 'Employment contracts with security responsibilities.', 'document', 'document_review', 'Provide sample employment contracts demonstrating inclusion of information security responsibilities, confidentiality obligations, acceptable use terms, and consequences of policy violations. Include both permanent and contractor agreements.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Contracts include security responsibilities and confidentiality obligations.', '{"Missing confidentiality clause","No security responsibilities defined","Contractor agreements different from policy"}', 'easy', 'high', true, '{"hr","employment","contracts","confidentiality"}'),

('A.6.3', 'ISO27001', 'Security Awareness Training Records', 'Evidence of information security awareness training completion.', 'training_record', 'system_export', 'Export training completion records from the LMS showing information security awareness training for all employees. Include completion rates, test scores, training content overview, and records of refresher training. Demonstrate training covers current threats and organizational policies.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'All employees completed security awareness training with passing scores.', '{"Completion rate below 95%","Training content outdated","No assessment scores recorded"}', 'easy', 'critical', true, '{"training","awareness","education"}'),

('A.6.4', 'ISO27001', 'Disciplinary Process Evidence', 'Documented disciplinary process for security violations.', 'policy_document', 'document_review', 'Provide the disciplinary process document for information security policy violations. Include the graduated sanctions framework, investigation procedures, appeal process, and evidence of process being communicated to all employees.', 'annually', 10, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Disciplinary process documented, communicated, and consistently applied.', '{"Process not communicated to staff","Missing investigation procedures","No appeal mechanism"}', 'easy', 'medium', true, '{"hr","disciplinary","policy"}'),

('A.6.5', 'ISO27001', 'Employment Termination Checklist Records', 'Evidence of security controls during employment termination.', 'document', 'document_review', 'Collect completed termination checklists for employees who left during the review period. Verify access revocation within required timeframes, asset return, knowledge transfer, and ongoing confidentiality obligations communicated.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Termination checklist completed for all departures with timely access revocation.', '{"Access not revoked within 24 hours","Missing asset return confirmation","Ongoing obligations not communicated"}', 'moderate', 'high', true, '{"hr","offboarding","termination","access-revocation"}'),

('A.6.6', 'ISO27001', 'Confidentiality Agreement Samples', 'Signed confidentiality and non-disclosure agreements.', 'document', 'document_review', 'Collect signed confidentiality and non-disclosure agreements for employees, contractors, and third parties with access to sensitive information. Verify agreements cover the scope of access, duration, and obligations after termination.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'NDAs signed by all personnel with access to sensitive information.', '{"Missing NDA for contractors","NDA scope too narrow","No post-termination obligations"}', 'easy', 'high', true, '{"nda","confidentiality","legal"}'),

('A.6.7', 'ISO27001', 'Remote Working Security Controls', 'Evidence of security controls for remote working.', 'configuration_export', 'system_export', 'Export VPN configurations, endpoint security settings, remote access policy configurations, and monitoring controls for remote workers. Include evidence of encrypted connections, endpoint protection, and data handling controls for remote work environments.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Remote working secured with VPN, endpoint protection, and encryption.', '{"VPN not mandatory","Missing endpoint protection","No data handling controls"}', 'moderate', 'high', true, '{"remote-work","vpn","endpoint-security"}'),

('A.6.8', 'ISO27001', 'Security Event Reporting Records', 'Evidence of security event reporting mechanism and usage.', 'system_report', 'system_export', 'Export records from the security event reporting system showing employee reports of security events, near-misses, and suspicious activities. Include response times, disposition of reports, and evidence of the reporting mechanism being communicated to staff.', 'quarterly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Active reporting mechanism with evidence of staff usage and timely response.', '{"No reports submitted","Reporting mechanism not communicated","Excessive response times"}', 'easy', 'medium', true, '{"incident-reporting","awareness","monitoring"}');

-- ============================================================
-- ISO 27001:2022 — Physical Controls (A.7)
-- ============================================================

INSERT INTO evidence_templates (framework_control_code, framework_code, name, description, evidence_category, collection_method, collection_instructions, collection_frequency, typical_collection_time_minutes, validation_rules, acceptance_criteria, common_rejection_reasons, difficulty, auditor_priority, is_system, tags) VALUES
('A.7.1', 'ISO27001', 'Physical Security Perimeter Documentation', 'Physical security perimeter definition and protection evidence.', 'document', 'document_review', 'Provide documentation defining physical security perimeters including floor plans showing secure areas, access control points, reception areas, and loading docks. Include evidence of physical barriers (walls, locked doors, manned reception) and monitoring (CCTV, alarms).', 'annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Perimeters defined with appropriate physical barriers and monitoring.', '{"Missing floor plans","Undefined secure areas","No monitoring at access points"}', 'moderate', 'high', true, '{"physical-security","perimeter","access-control"}'),

('A.7.2', 'ISO27001', 'Physical Entry Access Logs', 'Access logs for secure areas and data centers.', 'log_extract', 'system_export', 'Export physical access logs from card reader systems for secure areas and data centers. Include visitor logs, after-hours access records, and failed access attempt logs. Verify logs capture identity, timestamp, and access point for each entry.', 'monthly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Complete access logs with no unauthorized entries detected.', '{"Gaps in logging","Unauthorized access detected","Visitor logs incomplete"}', 'easy', 'high', true, '{"physical-security","access-logs","data-center"}'),

('A.7.3', 'ISO27001', 'Office and Room Security Evidence', 'Security arrangements for offices, rooms, and facilities.', 'screenshot', 'observation', 'Document security arrangements for offices and facilities through photographs and inspection records. Include evidence of locked cabinets, screen privacy filters, clean desk enforcement checks, and secure printing configurations.', 'semi_annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'Physical security controls observed and documented for work areas.', '{"Clean desk violations found","Unlocked cabinets observed","No privacy screens on public-facing terminals"}', 'easy', 'medium', true, '{"physical-security","clean-desk","office-security"}'),

('A.7.4', 'ISO27001', 'Physical Security Monitoring Evidence', 'CCTV and physical monitoring system evidence.', 'system_report', 'system_export', 'Provide evidence of physical security monitoring including CCTV coverage maps, monitoring schedules, alarm system test records, and retention periods for recordings. Include evidence of regular testing and maintenance of monitoring equipment.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Monitoring systems operational with adequate coverage and retention.', '{"CCTV coverage gaps","Monitoring not 24/7 for critical areas","Insufficient retention period"}', 'moderate', 'high', true, '{"physical-security","cctv","monitoring","surveillance"}'),

('A.7.5', 'ISO27001', 'Environmental Protection Evidence', 'Protection against environmental and physical threats.', 'document', 'document_review', 'Document environmental protection measures including fire suppression systems, flood protection, temperature and humidity monitoring, power protection (UPS, generators), and maintenance records. Include test results for environmental controls.', 'semi_annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'Environmental controls installed, tested, and maintained.', '{"Fire suppression not tested","No UPS for critical systems","Temperature monitoring gaps"}', 'moderate', 'high', true, '{"environmental","fire-suppression","power-protection"}'),

('A.7.6', 'ISO27001', 'Secure Area Working Procedures', 'Procedures and controls for working in secure areas.', 'procedure_document', 'document_review', 'Provide documented procedures for working in secure areas including access restrictions, supervision requirements, prohibition of recording devices, and physical security controls specific to secure areas such as server rooms and comms rooms.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Procedures documented covering supervision, device restrictions, and access control.', '{"No supervision requirements","Recording device policy missing","Procedures not communicated"}', 'easy', 'medium', true, '{"physical-security","secure-areas","procedures"}'),

('A.7.7', 'ISO27001', 'Clear Desk Clear Screen Audit', 'Audit results for clear desk and clear screen compliance.', 'audit_trail', 'observation', 'Conduct and document clear desk and clear screen audits. Record findings including unlocked workstations, sensitive documents left unattended, unlocked drawers, and visible passwords. Include remediation evidence for findings.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Audit conducted with high compliance rate and remediation of findings.', '{"High number of violations","No remediation actions","Audit not conducted"}', 'easy', 'medium', true, '{"clean-desk","clear-screen","physical-security","audit"}'),

('A.7.8', 'ISO27001', 'Equipment Placement and Protection Evidence', 'Evidence of secure equipment siting and protection.', 'document', 'observation', 'Document equipment placement and protection measures for critical IT equipment. Include server room photographs showing cable management, rack security, environmental controls proximity, and protection from physical and environmental threats.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Equipment securely placed with environmental and physical protection.', '{"Equipment exposed to environmental risks","Poor cable management","No physical protection for critical equipment"}', 'easy', 'medium', true, '{"equipment","data-center","physical-security"}'),

('A.7.9', 'ISO27001', 'Off-site Asset Security Records', 'Security controls for assets used off-premises.', 'document', 'document_review', 'Document security controls applied to assets taken off-site. Include laptop encryption verification, mobile device management configurations, equipment checkout records, and procedures for securing equipment during transit and at remote locations.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Off-site assets encrypted and tracked with security controls applied.', '{"Unencrypted laptops taken off-site","No equipment checkout process","Missing MDM enrollment"}', 'moderate', 'high', true, '{"mobile-security","encryption","asset-management"}'),

('A.7.10', 'ISO27001', 'Media Disposal Records', 'Secure disposal/destruction of storage media.', 'document', 'document_review', 'Collect records of secure media disposal including certificates of destruction, degaussing records, and disposal vendor agreements. Verify the chain of custody from decommissioning to destruction and that methods meet the required destruction standard.', 'quarterly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'All disposed media has destruction certificates with verified chain of custody.', '{"Missing destruction certificates","No chain of custody","Disposal method inadequate for classification"}', 'moderate', 'high', true, '{"media-disposal","destruction","data-sanitization"}');

-- ============================================================
-- ISO 27001:2022 — Technological Controls (A.8)
-- ============================================================

INSERT INTO evidence_templates (framework_control_code, framework_code, name, description, evidence_category, collection_method, collection_instructions, collection_frequency, typical_collection_time_minutes, validation_rules, acceptance_criteria, common_rejection_reasons, difficulty, auditor_priority, is_system, tags) VALUES
('A.8.1', 'ISO27001', 'Endpoint Security Configuration', 'User endpoint device security configurations.', 'configuration_export', 'system_export', 'Export endpoint security configurations from the endpoint management platform (e.g., Intune, SCCM, Jamf). Include antivirus/EDR status, encryption status (BitLocker/FileVault), patch levels, firewall settings, and USB device control policies.', 'monthly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'All endpoints encrypted, protected with EDR, and patched within policy timeframes.', '{"Unencrypted endpoints found","EDR not deployed on all devices","Critical patches outstanding"}', 'moderate', 'critical', true, '{"endpoint","encryption","edr","patching"}'),

('A.8.2', 'ISO27001', 'Privileged Access Management Evidence', 'Evidence of privileged access controls and monitoring.', 'system_report', 'system_export', 'Export privileged access management reports including PAM tool session recordings inventory, privileged account inventory, just-in-time access logs, and privileged activity monitoring alerts. Verify separation of admin and standard accounts.', 'monthly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Privileged access managed through PAM with session monitoring.', '{"Shared admin accounts found","No session monitoring","Missing just-in-time access","Standing privileges not minimized"}', 'hard', 'critical', true, '{"pam","privileged-access","monitoring"}'),

('A.8.3', 'ISO27001', 'Information Access Restriction Evidence', 'Technical access restriction configurations.', 'configuration_export', 'system_export', 'Export access control configurations from key applications and databases. Include role-based access control matrices, file share permissions, database access grants, and application permission settings. Verify least privilege implementation.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Access restrictions implement least privilege across all critical systems.', '{"Overly broad permissions found","Everyone group access to sensitive data","Missing RBAC implementation"}', 'moderate', 'high', true, '{"access-control","rbac","least-privilege"}'),

('A.8.4', 'ISO27001', 'Source Code Access Control Evidence', 'Access controls for source code repositories.', 'system_report', 'system_export', 'Export access control settings from source code repositories (GitHub, GitLab, Bitbucket). Include branch protection rules, required code reviews, commit signing configuration, and access audit logs showing who has access to which repositories.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Source code access restricted with branch protection and code review requirements.', '{"No branch protection","Open access to all repositories","Missing code review requirements"}', 'moderate', 'high', true, '{"source-code","repository","access-control","devops"}'),

('A.8.5', 'ISO27001', 'Secure Authentication Evidence', 'Multi-factor authentication and secure authentication configurations.', 'configuration_export', 'system_export', 'Export MFA enrollment reports and authentication configuration from identity providers (Azure AD, Okta, etc.). Include MFA coverage percentage, authentication policy settings, conditional access rules, and passwordless authentication deployment status.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'MFA enforced for all users on all critical systems.', '{"MFA coverage below 100%","Legacy authentication not blocked","No conditional access policies"}', 'moderate', 'critical', true, '{"mfa","authentication","identity"}'),

('A.8.6', 'ISO27001', 'Capacity Management Reports', 'System capacity monitoring and planning evidence.', 'system_report', 'automated_pull', 'Export capacity monitoring reports showing resource utilization trends for critical systems. Include CPU, memory, storage, and network bandwidth utilization with thresholds and alerting configuration. Provide evidence of capacity planning activities.', 'monthly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Capacity monitored with proactive planning to prevent performance issues.', '{"No capacity monitoring","Missing alerting thresholds","Capacity planning not documented"}', 'easy', 'medium', true, '{"capacity","monitoring","performance"}'),

('A.8.7', 'ISO27001', 'Anti-Malware Deployment Report', 'Malware protection deployment and detection evidence.', 'system_report', 'automated_pull', 'Export anti-malware deployment and detection reports from the endpoint protection platform. Include deployment coverage, signature update status, detection events, quarantine actions, and any exclusion policies. Verify all endpoints are protected and current.', 'monthly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Anti-malware deployed on all endpoints with current signatures.', '{"Missing deployment on some endpoints","Signatures outdated","Excessive exclusion policies"}', 'easy', 'critical', true, '{"anti-malware","endpoint-protection","detection"}'),

('A.8.8', 'ISO27001', 'Vulnerability Scan Reports', 'Technical vulnerability management scan results.', 'scan_report', 'automated_scan', 'Run and export vulnerability scan reports for internal and external infrastructure. Include vulnerability counts by severity, remediation progress from previous scans, mean time to remediate, and evidence of patch management. Cover servers, workstations, and network devices.', 'monthly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Regular scans with critical vulnerabilities remediated within SLA.', '{"Critical vulnerabilities not remediated","Scan coverage incomplete","Missing external scan","No trending data"}', 'moderate', 'critical', true, '{"vulnerability","scanning","patching","remediation"}'),

('A.8.9', 'ISO27001', 'Configuration Management Evidence', 'System configuration standards and compliance evidence.', 'configuration_export', 'system_export', 'Export system configuration compliance reports against hardening standards (CIS Benchmarks). Include baseline configurations, configuration drift detection results, and compliance percentages for servers, workstations, and network devices.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Systems configured per hardening standards with minimal drift.', '{"Significant configuration drift detected","Missing hardening baselines","Non-compliant systems found"}', 'hard', 'high', true, '{"configuration","hardening","cis-benchmark","baseline"}'),

('A.8.10', 'ISO27001', 'Data Deletion and Masking Evidence', 'Information deletion and masking implementation.', 'system_report', 'system_export', 'Export evidence of data deletion and masking controls. Include data retention policy enforcement reports, automated deletion logs, data masking configurations for non-production environments, and anonymization procedures for analytics data.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Data deletion automated per retention policy with masking in non-production.', '{"Non-production using live data","Missing retention enforcement","No masking configuration"}', 'hard', 'high', true, '{"data-deletion","masking","retention","privacy"}'),

('A.8.11', 'ISO27001', 'Data Masking Configuration Export', 'Data masking rules for non-production environments.', 'configuration_export', 'system_export', 'Export data masking configurations used for non-production environments. Include masking rules, covered data elements, verification of masking effectiveness, and access controls for unmasked production data.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'All sensitive data masked in non-production environments.', '{"Unmasked sensitive data in test environments","Incomplete masking rules","No verification testing"}', 'hard', 'high', true, '{"data-masking","non-production","privacy"}'),

('A.8.12', 'ISO27001', 'Data Leakage Prevention Evidence', 'DLP system configuration and detection reports.', 'system_report', 'system_export', 'Export DLP policy configurations and incident reports. Include policies for email, endpoint, cloud, and network DLP. Provide detection event logs, policy violation reports, and remediation actions taken for DLP alerts.', 'monthly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'DLP deployed across key channels with active policy enforcement.', '{"DLP not covering all channels","High false positive rate","No response to DLP alerts"}', 'hard', 'high', true, '{"dlp","data-protection","monitoring"}'),

('A.8.13', 'ISO27001', 'Backup Configuration and Test Records', 'Backup configuration and restoration testing evidence.', 'system_report', 'system_export', 'Export backup configuration details and restoration test records. Include backup schedules, retention settings, encryption configuration, off-site replication status, and results of periodic restoration tests. Verify backup coverage for all critical systems.', 'monthly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Backups configured, encrypted, replicated, and successfully tested.', '{"Backups not encrypted","Restoration test failed","Missing backup for critical systems","No off-site replication"}', 'moderate', 'critical', true, '{"backup","recovery","disaster-recovery","encryption"}'),

('A.8.14', 'ISO27001', 'System Redundancy Evidence', 'Redundancy and high availability configurations.', 'configuration_export', 'system_export', 'Export high availability and redundancy configurations for critical systems. Include load balancer configurations, database replication settings, failover cluster configurations, and evidence of redundancy testing.', 'semi_annually', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'Critical systems have documented redundancy with tested failover.', '{"Single points of failure for critical systems","Failover not tested","Missing redundancy documentation"}', 'hard', 'high', true, '{"redundancy","high-availability","failover"}'),

('A.8.15', 'ISO27001', 'Security Log Configuration and Samples', 'Logging configuration and log sample evidence.', 'log_extract', 'system_export', 'Export logging configuration from SIEM and key systems. Include log sources configured, retention settings, sample log entries showing security events, and alert rules. Verify logs capture authentication events, access changes, administrative actions, and system events.', 'monthly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Comprehensive logging configured with adequate retention and SIEM integration.', '{"Critical log sources missing","Insufficient retention","No SIEM integration","Missing security event types"}', 'hard', 'critical', true, '{"logging","siem","monitoring","audit-trail"}'),

('A.8.16', 'ISO27001', 'Security Monitoring and Alerting Evidence', 'Active security monitoring and alert response evidence.', 'system_report', 'system_export', 'Export security monitoring dashboards and alert reports from SIEM/SOC. Include alert volumes, response times, escalation records, and evidence of active monitoring for security events. Provide SOC operational procedures and shift coverage evidence.', 'monthly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Active 24/7 monitoring with defined response times and escalation.', '{"No 24/7 monitoring coverage","Alert response times exceed SLA","Missing escalation procedures"}', 'hard', 'critical', true, '{"soc","monitoring","alerting","siem"}'),

('A.8.17', 'ISO27001', 'Clock Synchronization Evidence', 'System clock synchronization configuration.', 'configuration_export', 'system_export', 'Export NTP configuration from servers, network devices, and security systems. Verify all systems synchronize to approved time sources, and demonstrate time accuracy across infrastructure for forensic and audit trail integrity.', 'semi_annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'All systems synchronized to approved NTP sources with verified accuracy.', '{"Systems not synchronized","Using unauthorized time sources","Time drift detected"}', 'easy', 'medium', true, '{"ntp","time-synchronization","logging"}'),

('A.8.18', 'ISO27001', 'Privileged Utility Control Evidence', 'Controls over system utility programs.', 'configuration_export', 'system_export', 'Document controls over privileged system utilities including application whitelisting configurations, restricted use of administrative tools, and monitoring of utility program usage. Include evidence of least privilege for utility access.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'System utilities restricted to authorized personnel with usage monitored.', '{"Unrestricted utility access","No monitoring of utility usage","Missing application whitelisting"}', 'moderate', 'medium', true, '{"utilities","privileged-access","application-control"}'),

('A.8.19', 'ISO27001', 'Software Installation Control Evidence', 'Controls over software installation on operational systems.', 'configuration_export', 'system_export', 'Export software installation control configurations including application whitelisting policies, software request and approval workflows, unauthorized software detection reports, and user privilege settings preventing unauthorized installations.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Software installation restricted with approval workflows and monitoring.', '{"Users have admin rights","No approval workflow","Unauthorized software detected"}', 'moderate', 'high', true, '{"software-control","application-whitelisting","installation"}'),

('A.8.20', 'ISO27001', 'Network Security Configuration', 'Network security controls and segmentation evidence.', 'configuration_export', 'system_export', 'Export network security configurations including firewall rules, network segmentation diagrams, VLAN configurations, IDS/IPS settings, and network access control lists. Verify separation of management, production, development, and DMZ networks.', 'quarterly', 35, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Network properly segmented with firewall rules implementing least privilege.', '{"Flat network architecture","Overly permissive firewall rules","Missing network segmentation"}', 'hard', 'critical', true, '{"network","firewall","segmentation","ids-ips"}'),

('A.8.21', 'ISO27001', 'Web Application Security Evidence', 'Security of web services and applications.', 'scan_report', 'automated_scan', 'Provide web application security testing results including OWASP Top 10 assessment, web application firewall configuration, HTTPS enforcement evidence, and penetration test results for web-facing applications.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Web applications tested against OWASP Top 10 with critical findings remediated.', '{"Critical vulnerabilities not remediated","WAF not configured","HTTPS not enforced","No penetration test conducted"}', 'hard', 'critical', true, '{"web-security","owasp","waf","penetration-testing"}'),

('A.8.22', 'ISO27001', 'Network Segmentation Verification', 'Network segmentation testing and verification results.', 'test_result', 'automated_scan', 'Run and export network segmentation verification tests. Include results of segmentation testing between security zones, evidence that critical systems are properly isolated, and verification that firewall rules effectively enforce segmentation.', 'semi_annually', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'Network segmentation verified with testing showing proper isolation.', '{"Segmentation bypasses found","Flat network detected","Missing isolation for critical systems"}', 'hard', 'high', true, '{"network","segmentation","testing","firewall"}'),

('A.8.23', 'ISO27001', 'Web Filtering Configuration', 'Web filtering and URL categorization evidence.', 'configuration_export', 'system_export', 'Export web filtering configurations including URL categorization policies, blocked categories, exception rules, and bypass audit logs. Include evidence of HTTPS inspection where deployed and user notification of filtering.', 'quarterly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Web filtering configured with appropriate category blocking and monitoring.', '{"No web filtering deployed","Excessive exceptions","No HTTPS inspection"}', 'easy', 'medium', true, '{"web-filtering","proxy","url-categorization"}'),

('A.8.24', 'ISO27001', 'Encryption Configuration Evidence', 'Cryptographic controls configuration.', 'configuration_export', 'system_export', 'Export encryption configurations for data at rest and in transit. Include TLS configurations, certificate inventory, disk encryption status, database encryption settings, key management procedures, and certificate expiration monitoring.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Strong encryption applied for data at rest and in transit with proper key management.', '{"Weak cipher suites configured","Missing encryption at rest","Key management inadequate","Expired certificates"}', 'hard', 'critical', true, '{"encryption","tls","key-management","certificates"}'),

('A.8.25', 'ISO27001', 'Secure Development Lifecycle Evidence', 'SDLC security practices documentation.', 'document', 'document_review', 'Document secure development lifecycle practices including security requirements, threat modeling, secure code review processes, SAST/DAST tool integration, security testing in CI/CD pipelines, and developer security training records.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Secure SDLC implemented with automated security testing in CI/CD.', '{"No security testing in pipeline","Missing threat modeling","No developer security training"}', 'hard', 'high', true, '{"sdlc","devsecops","code-review","sast-dast"}'),

('A.8.26', 'ISO27001', 'Application Security Requirements', 'Security requirements for application development.', 'document', 'document_review', 'Collect application security requirements documentation for recent development projects. Include security user stories, authentication/authorization requirements, input validation rules, encryption requirements, and security acceptance criteria.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Security requirements defined for all development projects.', '{"Missing security requirements","No input validation rules","Authentication requirements absent"}', 'moderate', 'high', true, '{"application-security","requirements","development"}'),

('A.8.27', 'ISO27001', 'Secure System Architecture Documentation', 'Secure architecture principles and implementation.', 'document', 'document_review', 'Provide secure system architecture documentation including architecture diagrams, security design patterns used, trust boundaries, data flow diagrams with security controls, and evidence of architecture review by security team.', 'annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Architecture reviewed by security with documented trust boundaries and controls.', '{"No security architecture review","Missing trust boundaries","Data flows not documented"}', 'hard', 'high', true, '{"architecture","design","security-review"}'),

('A.8.28', 'ISO27001', 'Secure Coding Standards and Review', 'Secure coding practices and code review evidence.', 'document', 'document_review', 'Provide secure coding standards documentation and code review evidence. Include SAST tool reports, code review records for security-sensitive changes, coding standards document, and developer training completion for secure coding practices.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Secure coding standards enforced with automated and manual code review.', '{"No SAST tool deployed","Code reviews not security-focused","Missing coding standards"}', 'hard', 'high', true, '{"secure-coding","code-review","sast","standards"}'),

('A.8.29', 'ISO27001', 'Security Testing in Development', 'Security testing during development and acceptance.', 'test_result', 'system_export', 'Export security testing results from CI/CD pipelines including SAST, DAST, SCA (software composition analysis), and container security scanning results. Include evidence of security acceptance testing before production deployment.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Security testing integrated in pipeline with blocking on critical findings.', '{"No security tests in pipeline","Critical findings not blocking deployment","Missing SCA scanning"}', 'hard', 'critical', true, '{"security-testing","ci-cd","sast","dast","sca"}'),

('A.8.30', 'ISO27001', 'Outsourced Development Security', 'Security controls for outsourced development.', 'document', 'document_review', 'Provide evidence of security controls for outsourced development including contractual security requirements, code ownership agreements, security testing requirements, access control for outsourced developers, and evidence of security oversight activities.', 'semi_annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'Outsourced development subject to security requirements and oversight.', '{"Missing contractual security requirements","No code security review","Unrestricted repository access"}', 'hard', 'high', true, '{"outsourcing","development","vendor","security"}'),

('A.8.31', 'ISO27001', 'Environment Separation Evidence', 'Separation of development, test, and production environments.', 'configuration_export', 'system_export', 'Export evidence of environment separation including network segmentation between environments, separate access controls, data protection in non-production environments, and change management controls for production deployments.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Environments properly separated with different access controls and data protection.', '{"Shared infrastructure between environments","Production data in test","Same credentials across environments"}', 'moderate', 'high', true, '{"environment-separation","development","testing","production"}'),

('A.8.32', 'ISO27001', 'Change Management Records', 'Change management process and records.', 'system_report', 'system_export', 'Export change management records from the change management system. Include change requests, impact assessments, approval records, implementation records, and post-implementation reviews. Sample recent changes across infrastructure and application layers.', 'monthly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Changes managed through formal process with approval and testing.', '{"Unauthorized changes detected","Missing impact assessment","No post-implementation review"}', 'moderate', 'critical', true, '{"change-management","itil","approval","deployment"}'),

('A.8.33', 'ISO27001', 'Test Data Management Evidence', 'Controls over test data protection.', 'document', 'document_review', 'Document test data management controls including procedures for generating synthetic test data, data masking/anonymization for production data used in testing, access controls for test environments, and evidence that personal data is not used directly in testing.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Test data properly managed with no unprotected personal data in test environments.', '{"Production data in test unmasked","No test data management procedure","Missing data anonymization"}', 'hard', 'high', true, '{"test-data","masking","privacy","non-production"}'),

('A.8.34', 'ISO27001', 'Audit System Protection Evidence', 'Protection of information system audit tools and data.', 'configuration_export', 'system_export', 'Export access control configurations for audit tools and audit data stores. Include SIEM access restrictions, audit log protection (immutability), separation of audit functions from operational functions, and evidence that audit tools are protected from unauthorized modification.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Audit tools and data protected with restricted access and immutability.', '{"Audit logs modifiable","Unrestricted access to audit tools","No log integrity protection"}', 'moderate', 'high', true, '{"audit","logging","integrity","access-control"}');

-- ============================================================
-- PCI DSS 4.0 — Key Controls
-- ============================================================

INSERT INTO evidence_templates (framework_control_code, framework_code, name, description, evidence_category, collection_method, collection_instructions, collection_frequency, typical_collection_time_minutes, validation_rules, acceptance_criteria, common_rejection_reasons, difficulty, auditor_priority, is_system, tags) VALUES
('1.2.1', 'PCI_DSS_4', 'Network Firewall Configuration Standards', 'Documented firewall and router configuration standards.', 'configuration_export', 'system_export', 'Export firewall configuration standards document and current running configurations. Verify configurations implement deny-all by default, restrict inbound/outbound traffic to that which is necessary for the cardholder data environment, and include justification for each allowed connection.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Firewall configurations match documented standards with deny-all default.', '{"Default allow rules found","Undocumented rules","Missing justification for allowed traffic"}', 'hard', 'critical', true, '{"pci","firewall","network","cde"}'),

('1.3.1', 'PCI_DSS_4', 'CDE Network Segmentation Verification', 'Penetration test verifying CDE network segmentation.', 'test_result', 'automated_scan', 'Conduct or provide results of network segmentation penetration testing that validates the CDE is properly isolated from non-CDE networks. Include test methodology, tools used, results showing no unauthorized connectivity, and remediation of any findings.', 'semi_annually', 45, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'Segmentation testing confirms CDE isolation with no bypass found.', '{"Segmentation bypass discovered","Test scope incomplete","Missing remediation of findings"}', 'expert', 'critical', true, '{"pci","segmentation","penetration-testing","cde"}'),

('2.2.1', 'PCI_DSS_4', 'System Hardening Standards', 'Configuration standards for system hardening.', 'document', 'document_review', 'Provide system hardening standards documents covering all system components in the CDE. Include CIS benchmark mappings, hardened images documentation, unnecessary service removal, and evidence of standards being applied to new deployments.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Hardening standards documented and applied to all CDE components.', '{"Standards not based on industry benchmarks","Missing coverage for all component types","Not applied to new deployments"}', 'hard', 'critical', true, '{"pci","hardening","cis-benchmark","configuration"}'),

('3.4.1', 'PCI_DSS_4', 'PAN Encryption Evidence', 'Evidence of primary account number encryption at rest.', 'configuration_export', 'system_export', 'Export encryption configurations for all locations where PAN is stored. Include database encryption settings (TDE, column-level), file-level encryption configurations, key management procedures, and evidence that PAN is rendered unreadable everywhere it is stored.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'PAN encrypted at rest in all storage locations with proper key management.', '{"Unencrypted PAN storage found","Weak encryption algorithm","Key management deficiencies"}', 'hard', 'critical', true, '{"pci","encryption","pan","key-management"}'),

('3.5.1', 'PCI_DSS_4', 'Encryption Key Management Procedures', 'Documented cryptographic key management procedures.', 'procedure_document', 'document_review', 'Provide key management procedures covering key generation, distribution, storage, rotation, retirement, and destruction. Include evidence of split knowledge and dual control for key management operations, and key custodian appointments.', 'annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Key management procedures cover full lifecycle with split knowledge.', '{"Missing key rotation schedule","No split knowledge","Key custodians not appointed"}', 'hard', 'critical', true, '{"pci","key-management","encryption","procedures"}'),

('4.2.1', 'PCI_DSS_4', 'TLS Configuration for PAN Transmission', 'Strong cryptography for PAN transmission.', 'configuration_export', 'system_export', 'Export TLS configurations for all systems transmitting PAN. Include TLS version settings (minimum TLS 1.2), cipher suite configurations, certificate details, and HSTS configurations. Verify no use of SSL or early TLS for PAN transmission.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'All PAN transmission uses TLS 1.2 or higher with strong cipher suites.', '{"TLS 1.0/1.1 still enabled","Weak cipher suites","Missing HSTS configuration"}', 'moderate', 'critical', true, '{"pci","tls","encryption","transmission"}'),

('5.2.1', 'PCI_DSS_4', 'Anti-Malware Solution Deployment Report', 'Anti-malware deployed on all CDE systems.', 'system_report', 'automated_pull', 'Export anti-malware deployment report covering all systems in the CDE. Include deployment status, signature update frequency, scan schedules, detection events, and evidence that anti-malware cannot be disabled by users. Verify all system types are covered.', 'monthly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Anti-malware deployed on all CDE systems with current signatures.', '{"Missing deployment on CDE systems","Signatures outdated","Users can disable protection"}', 'moderate', 'critical', true, '{"pci","anti-malware","endpoint","cde"}'),

('6.2.4', 'PCI_DSS_4', 'Software Security Practices Evidence', 'Secure software development practices for bespoke applications.', 'document', 'document_review', 'Provide evidence of secure software development practices for applications handling PAN. Include secure coding training records, SAST/DAST scan results, code review records for security vulnerabilities, and evidence of OWASP Top 10 coverage in testing.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Secure development practices with automated security testing for PAN applications.', '{"No SAST/DAST scanning","Missing secure coding training","OWASP Top 10 not covered"}', 'hard', 'critical', true, '{"pci","secure-development","sast","dast","owasp"}'),

('6.4.1', 'PCI_DSS_4', 'Web Application Firewall Configuration', 'WAF deployment and configuration for public-facing applications.', 'configuration_export', 'system_export', 'Export WAF configuration and deployment evidence for all public-facing web applications in the CDE. Include rule sets, custom rules, logging configuration, alert settings, and evidence of regular rule updates.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'WAF deployed and configured for all public-facing PCI applications.', '{"WAF not covering all applications","Rules not updated","Alert monitoring not configured"}', 'hard', 'critical', true, '{"pci","waf","web-application","firewall"}'),

('7.2.1', 'PCI_DSS_4', 'CDE Access Control Configuration', 'Role-based access control for CDE systems.', 'system_report', 'system_export', 'Export access control configurations for CDE systems. Include role definitions, user-to-role assignments, evidence of least privilege implementation, and access approval records. Verify that access is limited to personnel with a business need.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'RBAC implemented with least privilege and documented business justification.', '{"Overly broad access rights","Missing business justification","Shared accounts in CDE"}', 'hard', 'critical', true, '{"pci","access-control","rbac","cde","least-privilege"}'),

('8.3.1', 'PCI_DSS_4', 'Multi-Factor Authentication for CDE', 'MFA implementation for all CDE access.', 'configuration_export', 'system_export', 'Export MFA configuration for all access to the CDE including administrator access, remote access, and console access. Include MFA enrollment reports, authentication policy settings, and evidence that MFA cannot be bypassed.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'MFA enforced for all CDE access with no bypass mechanisms.', '{"MFA not required for all CDE access","Bypass mechanisms exist","Missing MFA for remote access"}', 'moderate', 'critical', true, '{"pci","mfa","authentication","cde"}'),

('8.6.1', 'PCI_DSS_4', 'Service Account Management Evidence', 'Management of application and service accounts.', 'system_report', 'system_export', 'Export service and application account inventory with documentation of purpose, owner, password rotation schedule, and access restrictions. Verify service accounts follow least privilege and have documented justification.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Service accounts inventoried with documented owners and restricted access.', '{"Orphaned service accounts","No password rotation","Overly permissive service accounts"}', 'hard', 'high', true, '{"pci","service-accounts","account-management"}'),

('9.4.1', 'PCI_DSS_4', 'Physical Access Controls for CDE', 'Physical access restrictions for areas containing cardholder data.', 'log_extract', 'system_export', 'Export physical access logs for areas containing cardholder data systems. Include badge reader logs, visitor logs, CCTV footage retention evidence, and access list management records. Verify only authorized personnel have physical access.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Physical access to CDE restricted and logged with authorized personnel list.', '{"Unauthorized physical access","Missing visitor logs","Access list not current"}', 'moderate', 'critical', true, '{"pci","physical-security","access-control","cde"}'),

('10.2.1', 'PCI_DSS_4', 'Audit Log Configuration for CDE', 'Audit logging enabled for all CDE components.', 'configuration_export', 'system_export', 'Export audit logging configurations for all CDE system components. Verify logging of user access, administrative actions, access to cardholder data, invalid access attempts, authentication events, and changes to audit logs. Include log retention evidence.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Comprehensive audit logging on all CDE components with 12-month retention.', '{"Missing logging on CDE components","Insufficient event types logged","Retention below 12 months"}', 'hard', 'critical', true, '{"pci","logging","audit-trail","cde","retention"}'),

('10.4.1', 'PCI_DSS_4', 'Log Monitoring and Review Evidence', 'Daily log review process and anomaly detection.', 'system_report', 'system_export', 'Export evidence of daily log review including SIEM alert reports, security analyst review records, automated anomaly detection results, and escalation records. Demonstrate that security events are identified and responded to within defined timeframes.', 'monthly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Daily log review with documented investigation of anomalies.', '{"Logs not reviewed daily","Alerts not investigated","No anomaly detection configured"}', 'hard', 'critical', true, '{"pci","log-review","monitoring","siem","soc"}'),

('11.3.1', 'PCI_DSS_4', 'Internal Vulnerability Scan Reports', 'Quarterly internal vulnerability scans of CDE.', 'scan_report', 'automated_scan', 'Run and provide internal vulnerability scan reports for all CDE systems. Include scan scope coverage, vulnerability findings by severity, remediation status, and evidence of rescanning after remediation. Verify all high-risk vulnerabilities are addressed.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Quarterly scans with no high-risk vulnerabilities remaining unaddressed.', '{"High-risk vulnerabilities not remediated","Incomplete scan coverage","No rescan after remediation"}', 'moderate', 'critical', true, '{"pci","vulnerability-scan","internal","cde"}'),

('11.3.2', 'PCI_DSS_4', 'ASV External Vulnerability Scan Reports', 'Quarterly external ASV vulnerability scans.', 'scan_report', 'automated_scan', 'Provide quarterly ASV (Approved Scanning Vendor) external vulnerability scan reports. Include passing scan results, remediation evidence for any failures, and ASV attestation of passing status. Verify scan covers all external-facing IP addresses and domains.', 'quarterly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Passing ASV scan with complete external scope coverage.', '{"ASV scan not passing","Missing external IP addresses","No ASV attestation"}', 'moderate', 'critical', true, '{"pci","asv","external-scan","vulnerability"}'),

('11.4.1', 'PCI_DSS_4', 'Penetration Test Report', 'Annual penetration test of CDE.', 'test_result', 'document_review', 'Provide the most recent penetration test report covering the CDE. Include test scope, methodology, findings by severity, exploitation evidence, remediation recommendations, and evidence of remediation for critical and high findings. Verify test was conducted by qualified testers.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Penetration test conducted by qualified testers with findings remediated.', '{"Scope incomplete","Critical findings not remediated","Tester not qualified","Missing network layer testing"}', 'hard', 'critical', true, '{"pci","penetration-testing","security-testing","cde"}'),

('12.1.1', 'PCI_DSS_4', 'Information Security Policy for PCI', 'Comprehensive information security policy for PCI compliance.', 'policy_document', 'document_review', 'Provide the information security policy covering PCI DSS requirements. Verify the policy addresses all PCI DSS requirements, is reviewed annually, updated when the environment changes, and disseminated to all relevant personnel. Include management approval evidence.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'PCI security policy current, approved, and disseminated to all personnel.', '{"Policy not reviewed annually","Missing management approval","Not covering all PCI requirements"}', 'moderate', 'critical', true, '{"pci","policy","governance"}'),

('12.6.1', 'PCI_DSS_4', 'PCI Security Awareness Training', 'Security awareness training for PCI-related personnel.', 'training_record', 'system_export', 'Export security awareness training records for all personnel with access to the CDE. Include training completion rates, assessment scores, training content covering PCI-specific topics (social engineering, password security, physical security), and evidence of annual refresher training.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'All CDE personnel completed PCI awareness training with passing scores.', '{"Incomplete training coverage","Training content not PCI-specific","No assessment scores"}', 'easy', 'high', true, '{"pci","training","awareness","cde"}'),

('12.10.1', 'PCI_DSS_4', 'Incident Response Plan for PCI', 'Incident response plan specific to payment card data.', 'procedure_document', 'document_review', 'Provide the incident response plan covering payment card data breaches. Include notification procedures for card brands and acquirers, evidence preservation for forensic investigation, roles and responsibilities, communication plan, and annual testing evidence.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'IRP covers card data breaches with brand notification and forensic procedures.', '{"Missing card brand notification procedures","No forensic preservation procedures","Plan not tested annually"}', 'hard', 'critical', true, '{"pci","incident-response","breach-notification","forensics"}');

-- ============================================================
-- NIST 800-53 Rev 5 — Key Controls
-- ============================================================

INSERT INTO evidence_templates (framework_control_code, framework_code, name, description, evidence_category, collection_method, collection_instructions, collection_frequency, typical_collection_time_minutes, validation_rules, acceptance_criteria, common_rejection_reasons, difficulty, auditor_priority, is_system, tags) VALUES
('AC-1', 'NIST_800_53', 'Access Control Policy and Procedures', 'Documented access control policy and procedures.', 'policy_document', 'document_review', 'Obtain the access control policy addressing purpose, scope, roles, responsibilities, management commitment, coordination, and compliance. Include procedures to facilitate implementation. Verify policy is reviewed and updated per organizational frequency.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Access control policy documented, approved, and reviewed within policy timeframe.', '{"Policy outdated","Missing procedures","No management approval"}', 'easy', 'high', true, '{"nist","access-control","policy","procedures"}'),

('AC-2', 'NIST_800_53', 'Account Management Records', 'Evidence of account lifecycle management.', 'system_report', 'system_export', 'Export account management records showing account creation, modification, disabling, and removal actions. Include approval workflows, periodic account reviews, and evidence of automated account management where implemented. Verify temporary and emergency accounts have defined timeframes.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Account lifecycle managed with approvals, reviews, and timely deprovisioning.', '{"Orphaned accounts found","Missing approval records","No periodic account review"}', 'moderate', 'critical', true, '{"nist","account-management","identity","lifecycle"}'),

('AC-3', 'NIST_800_53', 'Access Enforcement Configuration', 'Access enforcement mechanism configurations.', 'configuration_export', 'system_export', 'Export access enforcement configurations from operating systems, applications, and databases. Include discretionary and mandatory access control settings, access control lists, and role-based access control implementations.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Access enforcement implementing approved authorizations across all systems.', '{"Inconsistent access enforcement","Missing DAC/MAC implementation","Default permissions too permissive"}', 'hard', 'critical', true, '{"nist","access-control","enforcement","rbac"}'),

('AC-6', 'NIST_800_53', 'Least Privilege Implementation Evidence', 'Evidence of least privilege principle implementation.', 'system_report', 'system_export', 'Export evidence of least privilege implementation including privileged account inventory, privilege escalation procedures, just-in-time access logs, and evidence that functions are restricted to minimum necessary. Include evidence of privilege reviews.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Least privilege enforced with privileged access minimized and reviewed.', '{"Standing privileges not minimized","Missing privilege reviews","Over-provisioned accounts"}', 'hard', 'critical', true, '{"nist","least-privilege","privileged-access","pam"}'),

('AC-7', 'NIST_800_53', 'Unsuccessful Login Attempt Controls', 'Account lockout and failed login configurations.', 'configuration_export', 'system_export', 'Export account lockout configurations from all systems. Include lockout thresholds, lockout duration, automatic notification settings, and delay mechanisms for unsuccessful authentication attempts.', 'quarterly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Account lockout configured on all systems per organizational policy.', '{"No lockout configured","Threshold too high","Missing notification for lockouts"}', 'easy', 'high', true, '{"nist","authentication","lockout","brute-force"}'),

('AT-2', 'NIST_800_53', 'Security Awareness Training Program', 'Organization-wide security awareness and training program.', 'training_record', 'system_export', 'Export comprehensive security awareness training records including initial training for new users, annual refresher training, role-based training for specialized roles, and practical exercises. Include completion rates, assessment results, and training content updates.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'All personnel trained with role-based content and practical exercises.', '{"Incomplete training coverage","No role-based training","Training content outdated"}', 'moderate', 'high', true, '{"nist","training","awareness","education"}'),

('AU-2', 'NIST_800_53', 'Audit Event Configuration', 'Configuration of auditable events across systems.', 'configuration_export', 'system_export', 'Export audit event configurations from all information systems. Include configured audit events (authentication, privilege use, data access, configuration changes), event selection rationale, and coordination with organizational audit requirements.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Audit events configured per organizational requirements with adequate coverage.', '{"Missing critical event types","Inconsistent configuration across systems","No rationale documented"}', 'hard', 'critical', true, '{"nist","audit","logging","events"}'),

('AU-6', 'NIST_800_53', 'Audit Log Review and Analysis', 'Evidence of audit log review and analysis activities.', 'system_report', 'system_export', 'Export evidence of audit log review activities including SIEM correlation reports, analyst review records, anomaly investigations, and escalation records. Include evidence of automated analysis and integration of audit log review into security operations.', 'monthly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Audit logs reviewed per defined frequency with documented analysis.', '{"Reviews not conducted per schedule","No automated analysis","Findings not investigated"}', 'hard', 'critical', true, '{"nist","audit","log-review","analysis","siem"}'),

('CA-2', 'NIST_800_53', 'Security Assessment Plan and Results', 'Security control assessment plan and results.', 'document', 'document_review', 'Provide the security assessment plan including assessment scope, procedures, roles, and schedule. Include assessment results showing control effectiveness, identified weaknesses, and risk determinations. Verify assessments cover all applicable controls.', 'annually', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Assessment completed with documented results and risk determinations.', '{"Incomplete control coverage","Missing risk determinations","No assessment plan"}', 'hard', 'critical', true, '{"nist","assessment","security-controls","risk"}'),

('CA-7', 'NIST_800_53', 'Continuous Monitoring Strategy', 'Information security continuous monitoring strategy and results.', 'document', 'document_review', 'Provide the continuous monitoring strategy document including monitored controls, monitoring frequency, metrics, reporting mechanisms, and evidence of ongoing monitoring activities. Include sample monitoring reports and trend analysis.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Continuous monitoring strategy implemented with regular reporting.', '{"Strategy not implemented","Missing monitoring metrics","No trend analysis"}', 'hard', 'high', true, '{"nist","continuous-monitoring","strategy","metrics"}'),

('CM-2', 'NIST_800_53', 'Baseline Configuration Documentation', 'Documented baseline configurations for systems.', 'configuration_export', 'system_export', 'Export baseline configurations for all system types including servers, workstations, network devices, and security appliances. Include configuration standards, approved deviations with justification, and evidence of baseline enforcement through automated tools.', 'quarterly', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Baseline configurations documented and enforced for all system types.', '{"Missing baselines for system types","Unapproved deviations","No enforcement mechanism"}', 'hard', 'critical', true, '{"nist","baseline","configuration","hardening"}'),

('CM-3', 'NIST_800_53', 'Configuration Change Control Records', 'Records of configuration change control activities.', 'system_report', 'system_export', 'Export change control records including change requests, impact analyses, approval records, implementation records, and testing results. Include evidence of change review board activities and emergency change procedures.', 'monthly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Configuration changes managed through formal change control process.', '{"Unauthorized changes detected","Missing impact analysis","No change review board"}', 'moderate', 'critical', true, '{"nist","change-management","configuration","ccb"}'),

('CM-6', 'NIST_800_53', 'Configuration Settings Compliance', 'Evidence of configuration settings compliance with baselines.', 'scan_report', 'automated_scan', 'Run configuration compliance scans against established baselines. Export compliance reports showing conformance percentages, non-compliant settings identified, and remediation actions. Include CIS benchmark scan results and deviation justifications.', 'monthly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Systems compliant with configuration baselines with justified exceptions.', '{"Low compliance percentage","Unapproved deviations","No remediation plan for non-compliance"}', 'hard', 'critical', true, '{"nist","configuration","compliance","cis-benchmark","scanning"}'),

('CP-2', 'NIST_800_53', 'Contingency Plan Document', 'Organizational contingency plan for information systems.', 'document', 'document_review', 'Provide the contingency plan including essential missions, recovery objectives (RPO/RTO), roles and responsibilities, resource requirements, recovery procedures, and plan maintenance schedule. Verify alignment with business impact analysis.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Contingency plan documented with defined RPO/RTO aligned to BIA.', '{"Missing RPO/RTO","Plan not aligned with BIA","Outdated recovery procedures"}', 'moderate', 'critical', true, '{"nist","contingency","disaster-recovery","business-continuity"}'),

('CP-4', 'NIST_800_53', 'Contingency Plan Test Results', 'Results of contingency plan testing.', 'test_result', 'document_review', 'Provide contingency plan test results including test objectives, scenarios, participation records, results against recovery objectives, identified gaps, and corrective action plans. Verify tests include failover, recovery, and reconstitution activities.', 'annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Contingency plan tested with documented results and gap remediation.', '{"No test conducted","Recovery objectives not met","Missing corrective actions","Test scope too narrow"}', 'hard', 'critical', true, '{"nist","contingency-testing","disaster-recovery","exercise"}'),

('CP-9', 'NIST_800_53', 'Information System Backup Evidence', 'System backup configuration and testing evidence.', 'system_report', 'system_export', 'Export backup configuration details including backup schedules, types (full/incremental/differential), retention periods, encryption settings, off-site storage locations, and restoration test results. Verify backups cover all critical information and systems.', 'monthly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Backups configured, encrypted, stored off-site, and regularly tested.', '{"Backups not encrypted","No off-site storage","Restoration tests failing","Critical systems not backed up"}', 'moderate', 'critical', true, '{"nist","backup","recovery","encryption","storage"}'),

('IA-2', 'NIST_800_53', 'User Identification and Authentication', 'User identification and authentication mechanism evidence.', 'configuration_export', 'system_export', 'Export authentication configurations from identity providers and systems. Include MFA configuration, authentication policies, identity proofing procedures, and credential management settings. Verify unique identification for all users.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Unique identification and multi-factor authentication for all users.', '{"Shared accounts found","MFA not enforced","Missing identity proofing"}', 'moderate', 'critical', true, '{"nist","authentication","identity","mfa","identification"}'),

('IA-5', 'NIST_800_53', 'Authenticator Management Evidence', 'Evidence of password and credential management.', 'configuration_export', 'system_export', 'Export password policy configurations from all systems including minimum length, complexity requirements, expiration settings, history enforcement, and initial authenticator distribution procedures. Include evidence of credential vaulting and PKI management.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Authenticator management per NIST guidelines with strong password policies.', '{"Weak password requirements","No password history","Missing credential vaulting"}', 'moderate', 'high', true, '{"nist","passwords","credentials","pki","authentication"}'),

('IR-1', 'NIST_800_53', 'Incident Response Policy and Procedures', 'Documented incident response policy and procedures.', 'policy_document', 'document_review', 'Provide the incident response policy and detailed procedures covering incident detection, analysis, containment, eradication, recovery, and post-incident activity. Include roles, responsibilities, communication protocols, and escalation procedures.', 'annually', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'IR policy and procedures documented covering full incident lifecycle.', '{"Missing containment procedures","No communication protocols","Outdated procedures"}', 'moderate', 'critical', true, '{"nist","incident-response","policy","procedures"}'),

('IR-4', 'NIST_800_53', 'Incident Handling Records', 'Records of incident handling activities.', 'system_report', 'system_export', 'Export incident handling records from the incident management system. Include incident reports with detection, analysis, containment, eradication, and recovery actions documented. Verify incidents are categorized, tracked to resolution, and lessons learned documented.', 'quarterly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Incidents handled per procedures with complete documentation.', '{"Incomplete incident records","Missing containment actions","No lessons learned"}', 'moderate', 'critical', true, '{"nist","incident-handling","response","documentation"}'),

('IR-6', 'NIST_800_53', 'Incident Reporting Records', 'Evidence of incident reporting to authorities.', 'document', 'document_review', 'Provide records of incident reporting to appropriate authorities and organizations. Include reporting timelines, communication records, and evidence of reporting to US-CERT, law enforcement, or sector ISACs as required. Verify reporting meets required timeframes.', 'quarterly', 15, '[{"rule_type":"file_not_empty"}]', 'Reportable incidents communicated to authorities within required timeframes.', '{"Late reporting","Missing reports to required authorities","No reporting records"}', 'moderate', 'high', true, '{"nist","incident-reporting","us-cert","authorities"}'),

('MA-2', 'NIST_800_53', 'System Maintenance Records', 'Records of system maintenance activities.', 'system_report', 'system_export', 'Export maintenance records including scheduled and unscheduled maintenance activities, maintenance personnel authorization, remote maintenance session logs, and maintenance tool control records. Verify maintenance is performed per approved procedures.', 'quarterly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Maintenance activities documented with authorized personnel and tools.', '{"Unauthorized maintenance personnel","Missing maintenance records","No tool control"}', 'easy', 'medium', true, '{"nist","maintenance","system-administration"}'),

('MP-2', 'NIST_800_53', 'Media Access Control Evidence', 'Restrictions on access to digital and non-digital media.', 'document', 'document_review', 'Document media access controls including access restrictions for removable media, digital media, and non-digital media containing sensitive information. Include DLP policies for USB devices, encrypted removable media requirements, and media handling logs.', 'quarterly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Media access restricted with encryption for removable media.', '{"Unrestricted USB access","No removable media encryption","Missing media handling logs"}', 'moderate', 'high', true, '{"nist","media","removable-media","dlp","encryption"}'),

('PE-2', 'NIST_800_53', 'Physical Access Authorization Records', 'Authorization records for physical access.', 'document', 'system_export', 'Export physical access authorization records including authorized personnel lists, access approval forms, visitor authorization records, and escort procedures. Verify authorizations are current and reviewed periodically.', 'quarterly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Physical access authorized with current personnel lists and visitor controls.', '{"Outdated access lists","Missing visitor authorizations","No periodic review"}', 'easy', 'high', true, '{"nist","physical-access","authorization","visitor"}'),

('PE-3', 'NIST_800_53', 'Physical Access Control Evidence', 'Physical access control mechanisms and logs.', 'log_extract', 'system_export', 'Export physical access control logs from badge readers and security systems. Include entry/exit logs for secure facilities, after-hours access records, and physical intrusion alarm records. Verify physical access controls at all access points.', 'monthly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Physical access logged and monitored at all facility access points.', '{"Access points without logging","Alarm events not investigated","Missing after-hours logs"}', 'easy', 'high', true, '{"nist","physical-access","access-logs","badge"}'),

('PL-2', 'NIST_800_53', 'System Security Plan', 'Information system security plan document.', 'document', 'document_review', 'Provide the System Security Plan (SSP) for each major information system. Include system description, boundary definition, operating environment, security categorization, security control implementation descriptions, and authorization boundary diagram.', 'annually', 30, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'SSP documented with complete control implementation descriptions.', '{"Incomplete control descriptions","Missing system boundary","Outdated system description"}', 'hard', 'critical', true, '{"nist","ssp","security-plan","authorization"}'),

('PM-9', 'NIST_800_53', 'Risk Management Strategy', 'Organizational risk management strategy document.', 'document', 'document_review', 'Provide the risk management strategy including risk assessment methodology, risk tolerance levels, risk response procedures, and integration with organizational risk management framework. Verify alignment with NIST RMF.', 'annually', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Risk management strategy documented with defined risk tolerance.', '{"No risk tolerance defined","Missing risk response procedures","Not aligned with NIST RMF"}', 'hard', 'high', true, '{"nist","risk-management","strategy","rmf"}'),

('RA-3', 'NIST_800_53', 'Risk Assessment Results', 'Information system risk assessment results.', 'document', 'document_review', 'Provide risk assessment results including threat identification, vulnerability identification, impact analysis, likelihood determination, risk determination, and risk prioritization. Include both system-level and organizational risk assessments.', 'annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":365}}]', 'Risk assessment completed with documented threats, vulnerabilities, and risk levels.', '{"Missing threat analysis","Incomplete vulnerability identification","No risk prioritization"}', 'hard', 'critical', true, '{"nist","risk-assessment","threats","vulnerabilities"}'),

('RA-5', 'NIST_800_53', 'Vulnerability Scanning Results', 'Automated vulnerability scanning results and remediation.', 'scan_report', 'automated_scan', 'Run and export vulnerability scanning results for all information systems. Include authenticated and unauthenticated scans, vulnerability severity distribution, remediation timelines, and trending data. Verify scanning frequency meets organizational requirements.', 'monthly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Vulnerability scans conducted per schedule with timely remediation.', '{"Scans not conducted per schedule","Critical vulnerabilities unaddressed","Missing authenticated scans"}', 'moderate', 'critical', true, '{"nist","vulnerability","scanning","remediation"}'),

('SA-11', 'NIST_800_53', 'Developer Security Testing Results', 'Developer security testing and evaluation results.', 'test_result', 'system_export', 'Export developer security testing results including unit tests for security functions, integration testing results, SAST/DAST scan results, fuzz testing results, and security regression test results. Verify testing covers security requirements.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Security testing by developers with comprehensive coverage.', '{"No SAST/DAST scanning","Missing security unit tests","No fuzz testing"}', 'hard', 'high', true, '{"nist","security-testing","development","sast","dast"}'),

('SC-7', 'NIST_800_53', 'Boundary Protection Evidence', 'Network boundary protection configurations.', 'configuration_export', 'system_export', 'Export network boundary protection configurations including firewalls, proxies, gateways, and DMZ configurations. Include network architecture diagrams, traffic flow documentation, and evidence of monitoring at managed interfaces.', 'quarterly', 35, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'Network boundaries protected with monitored managed interfaces.', '{"Missing boundary protection","Unmonitored interfaces","Incomplete network diagrams"}', 'hard', 'critical', true, '{"nist","boundary-protection","firewall","network","dmz"}'),

('SC-8', 'NIST_800_53', 'Transmission Confidentiality Evidence', 'Protection of information during transmission.', 'configuration_export', 'system_export', 'Export encryption configurations for data in transit including TLS settings, VPN configurations, encrypted email settings, and certificate management. Verify all sensitive data transmissions use strong cryptographic protocols.', 'quarterly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":90}}]', 'All sensitive transmissions encrypted with strong cryptographic protocols.', '{"Unencrypted transmissions found","Weak protocols in use","Missing certificate management"}', 'moderate', 'critical', true, '{"nist","encryption","tls","vpn","transmission"}'),

('SC-12', 'NIST_800_53', 'Cryptographic Key Management', 'Cryptographic key establishment and management.', 'procedure_document', 'document_review', 'Provide cryptographic key management documentation including key generation procedures, key distribution methods, key storage protections, key rotation schedules, key destruction procedures, and key recovery mechanisms. Include evidence of PKI management.', 'semi_annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'Key management procedures documented and implemented for full lifecycle.', '{"Missing key rotation","No key destruction procedure","Inadequate key storage protection"}', 'hard', 'critical', true, '{"nist","key-management","encryption","pki","cryptography"}'),

('SC-13', 'NIST_800_53', 'Cryptographic Protection Evidence', 'FIPS-validated cryptographic modules evidence.', 'configuration_export', 'system_export', 'Export evidence of cryptographic module usage including FIPS 140-2/140-3 validation certificates, cryptographic algorithm configurations, and approved cryptographic module inventory. Verify cryptographic implementations meet federal requirements.', 'semi_annually', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":180}}]', 'FIPS-validated cryptographic modules used for all federal systems.', '{"Non-FIPS validated modules in use","Unapproved algorithms","Missing validation certificates"}', 'hard', 'critical', true, '{"nist","fips","cryptography","encryption","validation"}'),

('SI-2', 'NIST_800_53', 'Flaw Remediation Evidence', 'Software flaw identification and remediation records.', 'system_report', 'system_export', 'Export patch management reports showing identification of software flaws, testing of patches, deployment timelines, and compliance rates. Include evidence of patch management process covering all system types and meeting remediation timeframes.', 'monthly', 20, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Software flaws remediated within defined timeframes across all systems.', '{"Critical patches outstanding","Missing patch testing","Incomplete system coverage"}', 'moderate', 'critical', true, '{"nist","patching","flaw-remediation","vulnerability"}'),

('SI-3', 'NIST_800_53', 'Malicious Code Protection Evidence', 'Anti-malware deployment and management evidence.', 'system_report', 'automated_pull', 'Export malicious code protection reports including anti-malware deployment status, signature update status, real-time protection status, detection events, and false positive management. Verify protection at system entry and exit points.', 'monthly', 15, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Malicious code protection at all entry/exit points with current signatures.', '{"Missing protection at entry points","Outdated signatures","Real-time protection disabled"}', 'easy', 'critical', true, '{"nist","anti-malware","malicious-code","endpoint"}'),

('SI-4', 'NIST_800_53', 'Information System Monitoring Evidence', 'System monitoring configuration and results.', 'system_report', 'system_export', 'Export system monitoring configurations and results from IDS/IPS, SIEM, and monitoring tools. Include monitoring rules, alert configurations, detection events, and response records. Verify monitoring covers network, host, application, and data layers.', 'monthly', 25, '[{"rule_type":"file_not_empty"},{"rule_type":"date_within","params":{"days":30}}]', 'Comprehensive monitoring across all layers with active alerting.', '{"Missing monitoring layers","Alerts not investigated","No IDS/IPS deployment"}', 'hard', 'critical', true, '{"nist","monitoring","ids-ips","siem","detection"}');
